import{_ as t,a,b as d,c as i}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as r,o,c as l,a2 as n}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"WebDAV Channel شامل کریں","description":"","frontmatter":{},"headers":[],"relativePath":"ur/upload/webdav.md","filePath":"ur/upload/webdav.md","lastUpdated":1781962217000}'),s={name:"ur/upload/webdav.md"};function c(p,e,h,u,b,f){return o(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="webdav-channel-شامل-کریں" tabindex="-1">WebDAV Channel شامل کریں <a class="header-anchor" href="#webdav-channel-شامل-کریں" aria-label="Permalink to &quot;WebDAV Channel شامل کریں&quot;">​</a></h1><h2 id="کب-استعمال-کریں" tabindex="-1">کب استعمال کریں <a class="header-anchor" href="#کب-استعمال-کریں" aria-label="Permalink to &quot;کب استعمال کریں&quot;">​</a></h2><p>WebDAV channel اس وقت استعمال کریں جب:</p><ul><li>آپ کے پاس NAS، cloud drive، یا object storage service ہے جو WebDAV endpoint دیتی ہے۔</li><li>آپ چاہتے ہیں کہ uploaded images آپ کی اپنی WebDAV directory میں محفوظ ہوں۔</li><li>آپ credentials کو frontend میں لمبے عرصے تک expose کرنے کے بجائے D1 کی <code>upload_channels</code> table میں محفوظ رکھنا چاہتے ہیں۔</li></ul><h2 id="شروع-کرنے-سے-پہلے-کیا-چاہیے" tabindex="-1">شروع کرنے سے پہلے کیا چاہیے <a class="header-anchor" href="#شروع-کرنے-سے-پہلے-کیا-چاہیے" aria-label="Permalink to &quot;شروع کرنے سے پہلے کیا چاہیے&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ضرورت</th><th>مقصد</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>server-side WebDAV URL، مثلاً <code>https://nas.example.com/dav</code>۔</td></tr><tr><td>Username</td><td>WebDAV service میں sign in کرنے کے لیے۔</td></tr><tr><td>Password</td><td>WebDAV service میں sign in کرنے کے لیے۔</td></tr><tr><td>Authentication mode</td><td>default <code>Basic</code> ہے۔ <code>Digest</code> یا auto negotiation صرف اس وقت استعمال کریں جب server require کرے۔</td></tr><tr><td>Storage directory</td><td>files محفوظ کرنے کی directory۔ default <code>imgbed</code> ہے۔</td></tr></tbody></table><h2 id="کہاں-شامل-کریں" tabindex="-1">کہاں شامل کریں <a class="header-anchor" href="#کہاں-شامل-کریں" aria-label="Permalink to &quot;کہاں شامل کریں&quot;">​</a></h2><ol><li>System Settings کھولیں۔</li><li>Upload Settings میں جائیں۔</li><li>اوپر دائیں طرف Add Channel پر کلک کریں۔</li><li><code>WebDAV</code> منتخب کریں۔</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>کام</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>اس WebDAV channel کا واضح نام، مثلاً <code>koofr</code> یا <code>nas</code>۔</td><td>Yes</td></tr><tr><td>Endpoint</td><td>مکمل WebDAV endpoint، <code>https://</code> سمیت۔</td><td>Yes</td></tr><tr><td>Username</td><td>WebDAV login username۔</td><td>Yes</td></tr><tr><td>Password</td><td>WebDAV login password۔</td><td>Yes</td></tr><tr><td>Authentication mode</td><td>عموماً <code>Basic</code>؛ اگر server digest authentication require کرے تو <code>Digest</code> استعمال کریں۔</td><td>Yes</td></tr><tr><td>Storage directory</td><td>جہاں files محفوظ ہوں گی۔ default <code>imgbed</code> ہے۔</td><td>No</td></tr></tbody></table><h2 id="مثال-fie-nl-tab-digital" tabindex="-1">مثال: fie.nl.tab.digital <a class="header-anchor" href="#مثال-fie-nl-tab-digital" aria-label="Permalink to &quot;مثال: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-app-password-بنائیں" tabindex="-1">1. App Password بنائیں <a class="header-anchor" href="#_1-app-password-بنائیں" aria-label="Permalink to &quot;1. App Password بنائیں&quot;">​</a></h3><p>اپنے account security settings کھولیں، application passwords تلاش کریں، اور نیا app password بنائیں۔</p><p><img src="'+t+'" alt="Create an app password" loading="lazy"></p><p>بننے کے بعد نیا app password copy کر کے محفوظ کریں۔ عموماً یہ صرف ایک بار دکھایا جاتا ہے۔</p><p><img src="'+a+'" alt="Save the new app password" loading="lazy"></p><h3 id="_2-imgbed-میں-webdav-configuration-بھریں" tabindex="-1">2. ImgBed میں WebDAV Configuration بھریں <a class="header-anchor" href="#_2-imgbed-میں-webdav-configuration-بھریں" aria-label="Permalink to &quot;2. ImgBed میں WebDAV Configuration بھریں&quot;">​</a></h3><p>ImgBed پر واپس آئیں اور WebDAV channel شامل کریں:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Endpoint</td><td><code>https://fie.nl.tab.digital/</code> کی طرف سے دیا گیا WebDAV URL۔</td></tr><tr><td>Username</td><td>آپ کا WebDAV username۔</td></tr><tr><td>Password</td><td>ابھی بنایا ہوا app password۔</td></tr><tr><td>Authentication mode</td><td>زیادہ تر cases میں <code>Basic</code> سے شروع کریں۔</td></tr><tr><td>Storage directory</td><td>default <code>imgbed</code> ہے؛ custom directory بھی استعمال کر سکتے ہیں۔</td></tr></tbody></table><p><img src="'+d+'" alt="Fill in the configuration" loading="lazy"></p><h2 id="large-file-upload-behavior" tabindex="-1">Large File Upload Behavior <a class="header-anchor" href="#large-file-upload-behavior" aria-label="Permalink to &quot;Large File Upload Behavior&quot;">​</a></h2><p>WebDAV channel اب real session-based chunked upload استعمال کرتا ہے۔</p><p>چھوٹی files ایک مکمل file کے طور پر upload ہوتی ہیں۔ 64 MiB سے بڑی files تقریباً 10 MiB کے chunks میں خودکار طور پر تقسیم ہو کر remote chunk directory میں upload ہوتی ہیں۔</p><p>WebDAV service کو <code>partial update</code> یا offset-based writes support کرنے کی ضرورت نہیں۔ ImgBed remote server پر chunks کو ایک بڑی file میں merge نہیں کرتا۔ اس کے بجائے chunk manifest محفوظ کرتا ہے اور file request ہونے پر chunks کو ترتیب سے پڑھتا ہے۔</p><p>عملی طور پر:</p><table tabindex="0"><thead><tr><th>File Size</th><th>Upload Method</th><th>Remote Storage Layout</th></tr></thead><tbody><tr><td>64 MiB یا کم</td><td>Normal upload</td><td>ایک مکمل file</td></tr><tr><td>64 MiB سے زیادہ</td><td>Real session chunked upload</td><td>chunk directory جس میں متعدد chunk files ہوں</td></tr></tbody></table><p>chunk directory صرف remote storage layout پر اثر ڈالتی ہے۔ ImgBed میں file URL نہیں بدلتا۔ users پھر بھی اصل <code>/file/...</code> link سے file access کرتے ہیں۔</p><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Upload Settings کھولیں۔</li><li>Add Channel پر کلک کریں۔</li><li><code>WebDAV</code> منتخب کریں۔</li><li>قابل شناخت channel name درج کریں، مثلاً <code>koofr</code>۔</li><li>WebDAV endpoint درج کریں، مثلاً <code>https://app.koofr.net/dav/Koofr</code>۔</li><li>username اور password درج کریں۔</li><li>authentication mode کو default طور پر <code>Basic</code> رہنے دیں۔</li><li>storage directory کو <code>imgbed</code> رہنے دیں، یا اپنی directory درج کریں۔</li><li>Save پر کلک کریں۔</li><li>Save کے بعد channel card چیک کریں، capacity query دستیاب ہو تو چلائیں، اور test file upload کریں۔</li></ol><h2 id="verify-کیسے-کریں" tabindex="-1">Verify کیسے کریں <a class="header-anchor" href="#verify-کیسے-کریں" aria-label="Permalink to &quot;Verify کیسے کریں&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Verify کرنے کا طریقہ</th></tr></thead><tbody><tr><td>Channel card appears</td><td>Save کے بعد Upload Settings میں WebDAV channel card نظر آنا چاہیے۔</td></tr><tr><td>Channel is enabled</td><td>card کے اوپر دائیں switch کو on رہنا چاہیے۔</td></tr><tr><td>Credentials are saved</td><td>detail view میں Endpoint، username، authentication mode، اور storage directory دکھنے چاہئیں۔</td></tr><tr><td>Small file upload works</td><td>test image upload کریں اور confirm کریں کہ file WebDAV directory میں آ گئی ہے۔</td></tr><tr><td>Large file rule works</td><td>64 MiB سے بڑی files chunked upload استعمال کرتی ہیں اور remote chunk directory بناتی ہیں۔</td></tr><tr><td>Capacity query works</td><td>server capacity information support کرے تو query used اور total capacity دکھائے گی۔</td></tr></tbody></table><p><img src="'+i+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="بڑی-webdav-files-chunk-directory-کیوں-بناتی-ہیں؟" tabindex="-1">بڑی WebDAV files chunk directory کیوں بناتی ہیں؟ <a class="header-anchor" href="#بڑی-webdav-files-chunk-directory-کیوں-بناتی-ہیں؟" aria-label="Permalink to &quot;بڑی WebDAV files chunk directory کیوں بناتی ہیں؟&quot;">​</a></h3><p>یہ بڑی files کے لیے موجودہ storage method ہے۔</p><p>64 MiB سے بڑی files remote side پر ایک بڑی file میں merge نہیں ہوتیں۔ وہ chunk directory کے طور پر محفوظ ہوتی ہیں۔ ImgBed chunk manifest record کرتا ہے اور complete content chunks کو ترتیب سے پڑھ کر واپس کرتا ہے۔</p><h3 id="large-file-upload-fail-ہو-تو-پہلے-کیا-چیک-کریں؟" tabindex="-1">large file upload fail ہو تو پہلے کیا چیک کریں؟ <a class="header-anchor" href="#large-file-upload-fail-ہو-تو-پہلے-کیا-چیک-کریں؟" aria-label="Permalink to &quot;large file upload fail ہو تو پہلے کیا چیک کریں؟&quot;">​</a></h3><p>سب سے پہلے Endpoint، username، password، اور storage directory چیک کریں۔ پھر confirm کریں کہ WebDAV service directory creation، file writing، اور file reading allow کرتی ہے۔</p><p>اگر capacity query fail ہو لیکن small file upload کام کرے، تو server شاید capacity reporting support نہیں کرتا یا restrict کرتا ہے۔ اس کا لازمی مطلب یہ نہیں کہ upload unavailable ہے۔</p><h3 id="کون-سا-authentication-mode-استعمال-کروں؟" tabindex="-1">کون سا authentication mode استعمال کروں؟ <a class="header-anchor" href="#کون-سا-authentication-mode-استعمال-کروں؟" aria-label="Permalink to &quot;کون سا authentication mode استعمال کروں؟&quot;">​</a></h3><p><code>Basic</code> سے شروع کریں۔</p><p>اگر server واضح طور پر digest authentication require کرے تو <code>Digest</code> استعمال کریں۔</p><p>یقین نہ ہو تو automatic negotiation استعمال کریں۔</p><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebDAV endpoint, username, اور password تیار کریں</span></span>
<span class="line"><span>-&gt; Upload Settings کھولیں</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; WebDAV منتخب کریں</span></span>
<span class="line"><span>-&gt; Endpoint / username / password درج کریں</span></span>
<span class="line"><span>-&gt; default طور پر authentication mode Basic رکھیں</span></span>
<span class="line"><span>-&gt; default طور پر storage directory imgbed رکھیں</span></span>
<span class="line"><span>-&gt; Save کریں</span></span>
<span class="line"><span>-&gt; capacity query کریں</span></span>
<span class="line"><span>-&gt; test file upload کریں</span></span></code></pre></div>`,45)])])}const k=r(s,[["render",c]]);export{y as __pageData,k as default};
